INSERT INTO `testimonials` (`id`, `name`, `company`, `position`, `content`, `rating`, `photo`, `is_active`, `order`, `created_at`, `updated_at`) VALUES ('1', 'Bpk. Budi Santoso', 'PT. Manufaktur Sukses', 'Manager', 'Suhu di dalam pabrik kami turun signifikan setelah memasang Cyclevent CV-90. Pekerja jadi lebih nyaman dan produktivitas meningkat tajam. Sangat direkomendasikan!', '5', 'testimonials/kkLLSYBkmrah.webp', '1', '1', '2026-07-02 02:12:59', '2026-07-04 14:50:53');
INSERT INTO `testimonials` (`id`, `name`, `company`, `position`, `content`, `rating`, `photo`, `is_active`, `order`, `created_at`, `updated_at`) VALUES ('2', 'Pak Bara', 'PT. Logistik Cepat', 'Warehouse Head', 'Awalnya ragu karena tanpa listrik, tapi ternyata perputarannya sangat stabil dan kuat. Masalah udara pengap di gudang langsung teratasi.', '5', 'testimonials/ZD7XUD4MhvHj.webp', '1', '2', '2026-07-02 02:12:59', '2026-07-03 19:56:31');
INSERT INTO `testimonials` (`id`, `name`, `company`, `position`, `content`, `rating`, `photo`, `is_active`, `order`, `created_at`, `updated_at`) VALUES ('3', 'H. Ahmad', 'Owner', 'Pabrik Tekstil Balaraja', 'Pelayanan dari Cyclevent sangat memuaskan. Mulai dari survei, rekomendasi ukuran, hingga instalasi berjalan dengan rapi. Garansi 15 tahun bikin tenang.', '5', 'testimonials/S3Wf9e6tLs9y.webp', '1', '3', '2026-07-02 02:12:59', '2026-07-03 15:26:00');
